+import { UserProfileWithHistory } from "@/types/userProfile";
+
+const userProfileKey = "userProfile";
+
+const defaultProfile: UserProfileWithHistory = {
+  totalXP: 0,
+  level: 1,
+  questionsAnswered: 0,
+  correctAnswers: 0,
+  incorrectAnswers: 0,
+  answeredQuestionIds: [],
+  lastUpdated: new Date(0).toISOString(),
+};
+
+function calculateLevel(totalXP: number) {
+  return Math.max(1, Math.floor(totalXP / 500) + 1);
+}
+
+function readProfile(): UserProfileWithHistory {
+  if (typeof window === "undefined") {
+    return defaultProfile;
+  }
+
+  try {
+    const storedProfile = window.localStorage.getItem(userProfileKey);
+    return storedProfile
+      ? { ...defaultProfile, ...JSON.parse(storedProfile) }
+      : defaultProfile;
+  } catch {
+    return defaultProfile;
+  }
+}
+
+function saveProfile(profile: UserProfileWithHistory) {
+  const updatedProfile = {
+    ...profile,
+    level: calculateLevel(profile.totalXP),
+    lastUpdated: new Date().toISOString(),
+  };
+
+  if (typeof window !== "undefined") {
+    window.localStorage.setItem(userProfileKey, JSON.stringify(updatedProfile));
+  }
+
+  return updatedProfile;
+}
+
+export function getUserProfile() {
+  return readProfile();
+}
+
+export function addXPForCorrectAnswer(
+  questionId: string,
+  scoreBandRange = 1
+) {
+  const profile = readProfile();
+  const alreadyAnswered = profile.answeredQuestionIds.includes(questionId);
+  const xpGain = Math.max(1, scoreBandRange) * 10;
+
+  return saveProfile({
+    ...profile,
+    totalXP: profile.totalXP + xpGain,
+    questionsAnswered: alreadyAnswered
+      ? profile.questionsAnswered
+      : profile.questionsAnswered + 1,
+    correctAnswers: profile.correctAnswers + 1,
+    answeredQuestionIds: alreadyAnswered
+      ? profile.answeredQuestionIds
+      : [...profile.answeredQuestionIds, questionId],
+  });
+}
+
+export function reduceXPForIncorrectAnswer(
+  questionId: string,
+  scoreBandRange = 1
+) {
+  const profile = readProfile();
+  const alreadyAnswered = profile.answeredQuestionIds.includes(questionId);
+  const xpLoss = Math.floor((Math.max(1, scoreBandRange) * 10) / 2);
+
+  return saveProfile({
+    ...profile,
+    totalXP: Math.max(0, profile.totalXP - xpLoss),
+    questionsAnswered: alreadyAnswered
+      ? profile.questionsAnswered
+      : profile.questionsAnswered + 1,
+    incorrectAnswers: profile.incorrectAnswers + 1,
+    answeredQuestionIds: alreadyAnswered
+      ? profile.answeredQuestionIds
+      : [...profile.answeredQuestionIds, questionId],
+  });
+}
