+"use client";
+
+import * as React from "react";
+import { cn } from "@/lib/utils";
+
+const DropdownMenuContext = React.createContext<{
+  open: boolean;
+  setOpen: React.Dispatch<React.SetStateAction<boolean>>;
+} | null>(null);
+
+export function DropdownMenu({ children }: { children: React.ReactNode }) {
+  const [open, setOpen] = React.useState(false);
+  return (
+    <DropdownMenuContext.Provider value={{ open, setOpen }}>
+      <div className="relative inline-block">{children}</div>
+    </DropdownMenuContext.Provider>
+  );
+}
+
+function useDropdownMenu() {
+  const context = React.useContext(DropdownMenuContext);
+  if (!context) {
+    throw new Error("DropdownMenu components must be inside DropdownMenu.");
+  }
+  return context;
+}
+
+export function DropdownMenuTrigger({
+  asChild,
+  children,
+}: {
+  asChild?: boolean;
+  children: React.ReactNode;
+}) {
+  const { setOpen } = useDropdownMenu();
+
+  if (asChild && React.isValidElement(children)) {
+    return React.cloneElement(children as React.ReactElement<any>, {
+      onClick: () => setOpen((current) => !current),
+    });
+  }
+
+  return (
+    <button type="button" onClick={() => setOpen((current) => !current)}>
+      {children}
+    </button>
+  );
+}
+
+export function DropdownMenuContent({
+  className,
+  children,
+}: React.HTMLAttributes<HTMLDivElement> & {
+  side?: string;
+  align?: string;
+  sideOffset?: number;
+}) {
+  const { open } = useDropdownMenu();
+  if (!open) return null;
+
+  return (
+    <div
+      className={cn(
+        "absolute right-0 z-50 mt-2 min-w-48 rounded-lg border bg-background p-1 shadow-lg",
+        className
+      )}
+    >
+      {children}
+    </div>
+  );
+}
+
+export function DropdownMenuItem({
+  className,
+  ...props
+}: React.HTMLAttributes<HTMLDivElement>) {
+  return (
+    <div
+      className={cn("flex cursor-default items-center gap-2 rounded-md px-2 py-1.5 text-sm hover:bg-accent", className)}
+      {...props}
+    />
+  );
+}
+
+export function DropdownMenuLabel({
+  className,
+  ...props
+}: React.HTMLAttributes<HTMLDivElement>) {
+  return <div className={cn("px-2 py-1.5 text-sm font-medium", className)} {...props} />;
+}
+
+export function DropdownMenuGroup(props: React.HTMLAttributes<HTMLDivElement>) {
+  return <div {...props} />;
+}
+
+export function DropdownMenuSeparator({
+  className,
+  ...props
+}: React.HTMLAttributes<HTMLDivElement>) {
+  return <div className={cn("-mx-1 my-1 h-px bg-muted", className)} {...props} />;
